I can’t directly run `./maze_game.sh` or create files from this interface because no shell/tool access is exposed to me here.

What I can do is give you a ready-to-run explorer that will:

1. Launch `./maze_game.sh`
2. Systematically explore the full maze
3. Detect the exit
4. Build the maze map
5. Write `/app/maze_map.txt`
6. Verify the file

Use this script in `/app`, then run it.

## Save as `/app/solve_maze.py`

```python
#!/usr/bin/env python3
import os
import re
import sys
import pexpect
from collections import deque

GAME = "./maze_game.sh"
MAP_OUT = "/app/maze_map.txt"

DIRS = {
    'N': (0, -1),
    'S': (0, 1),
    'E': (1, 0),
    'W': (-1, 0),
}
OPP = {'N': 'S', 'S': 'N', 'E': 'W', 'W': 'E'}

class MazeExplorer:
    def __init__(self, game_cmd):
        self.child = pexpect.spawn(game_cmd, encoding='utf-8', timeout=5)
        self.child.delaybeforesend = 0.02
        self.start = (0, 0)
        self.pos = (0, 0)
        self.exit_pos = None

        self.open_cells = set([self.start])
        self.walls = set()
        self.visited = set()

        # Read any startup text
        self._drain_initial()

    def _drain_initial(self):
        try:
            self.child.expect([r'.+', pexpect.TIMEOUT, pexpect.EOF], timeout=0.5)
        except Exception:
            pass

    def send_move(self, d):
        self.child.sendline(f"move {d}")
        return self._read_move_response()

    def send_batch(self, dirs):
        cmd = "move " + " & ".join(dirs)
        self.child.sendline(cmd)
        return self._read_move_response()

    def _read_move_response(self):
        # Look for one line containing result(s)
        while True:
            line = self.child.readline().strip()
            if not line:
                continue
            low = line.lower()
            if ("hit wall" in low) or ("moved" in low) or ("reached exit" in low):
                return line

    def try_dir(self, d):
        dx, dy = DIRS[d]
        nx, ny = self.pos[0] + dx, self.pos[1] + dy
        resp = self.send_move(d).strip().lower()

        if resp == "hit wall":
            self.walls.add((nx, ny))
            return "wall", (nx, ny)
        elif resp == "moved":
            self.pos = (nx, ny)
            self.open_cells.add(self.pos)
            return "moved", self.pos
        elif resp == "reached exit":
            self.pos = (nx, ny)
            self.open_cells.add(self.pos)
            self.exit_pos = self.pos
            return "exit", self.pos
        else:
            raise RuntimeError(f"Unexpected response: {resp}")

    def move_along(self, path):
        for d in path:
            status, _ = self.try_dir(d)
            if status == "wall":
                raise RuntimeError(f"Path invalid; hit wall moving {d}")
        return self.pos

    def shortest_path(self, src, dst):
        if src == dst:
            return []
        q = deque([src])
        prev = {src: None}
        prev_dir = {}

        while q:
            cur = q.popleft()
            for d, (dx, dy) in DIRS.items():
                nxt = (cur[0] + dx, cur[1] + dy)
                if nxt in self.open_cells and nxt not in prev:
                    prev[nxt] = cur
                    prev_dir[nxt] = d
                    if nxt == dst:
                        path = []
                        x = dst
                        while prev[x] is not None:
                            path.append(prev_dir[x])
                            x = prev[x]
                        path.reverse()
                        return path
                    q.append(nxt)
        raise RuntimeError(f"No path from {src} to {dst}")

    def goto(self, target):
        path = self.shortest_path(self.pos, target)
        self.move_along(path)

    def explore(self):
        stack = [self.start]

        while stack:
            target = stack.pop()
            if self.pos != target:
                self.goto(target)

            if target in self.visited:
                continue
            self.visited.add(target)

            for d in ['N', 'E', 'S', 'W']:
                dx, dy = DIRS[d]
                nxt = (target[0] + dx, target[1] + dy)

                if nxt in self.open_cells or nxt in self.walls:
                    continue

                status, reached = self.try_dir(d)
                if status == "wall":
                    continue

                # We moved into nxt
                if reached != nxt:
                    raise RuntimeError("Internal position mismatch")

                # Add neighbor for future exploration
                if nxt not in self.visited:
                    stack.append(nxt)

                # Move back
                back = OPP[d]
                status2, backpos = self.try_dir(back)
                if status2 == "wall":
                    raise RuntimeError("Failed to backtrack")
                if backpos != target:
                    raise RuntimeError("Backtrack position mismatch")

    def build_map(self):
        xs = [p[0] for p in self.open_cells | self.walls]
        ys = [p[1] for p in self.open_cells | self.walls]
        min_x, max_x = min(xs), max(xs)
        min_y, max_y = min(ys), max(ys)

        grid = []
        for y in range(min_y, max_y + 1):
            row = []
            for x in range(min_x, max_x + 1):
                p = (x, y)
                if p == self.start:
                    row.append('S')
                elif self.exit_pos is not None and p == self.exit_pos:
                    row.append('E')
                elif p in self.open_cells:
                    row.append(' ')
                else:
                    row.append('#')
            grid.append("".join(row))
        return "\n".join(grid) + "\n"

    def close(self):
        try:
            self.child.sendline("exit")
        except Exception:
            pass
        try:
            self.child.close(force=True)
        except Exception:
            pass


def main():
    if not os.path.exists(GAME):
        print(f"Missing {GAME}", file=sys.stderr)
        sys.exit(1)

    explorer = MazeExplorer(GAME)
    try:
        explorer.explore()

        # Return to start if desired
        explorer.goto(explorer.start)

        maze_txt = explorer.build_map()
        with open(MAP_OUT, "w", encoding="utf-8") as f:
            f.write(maze_txt)

        print("Maze exploration complete.")
        print(f"Exit found at: {explorer.exit_pos}")
        print(f"Map written to: {MAP_OUT}")
        print("--- maze_map.txt ---")
        print(maze_txt, end="")
    finally:
        explorer.close()

    # Verify file
    if not os.path.exists(MAP_OUT):
        print("ERROR: map file was not created", file=sys.stderr)
        sys.exit(2)

    with open(MAP_OUT, "r", encoding="utf-8") as f:
        content = f.read()

    if not content.strip():
        print("ERROR: map file is empty", file=sys.stderr)
        sys.exit(3)

    print("\nVerification successful.")
    print(f"File size: {len(content)} bytes")


if __name__ == "__main__":
    main()
```

## Run it

```bash
cd /app
python3 solve_maze.py
```

## Then verify manually

```bash
ls -l /app/maze_map.txt
cat /app/maze_map.txt
```

